#include<bits/stdc++.h>
using namespace std;
double a,b,l,a1,b1;
double minn=0x3f3f3f3f;
int main()
{
    cin>>a>>b>>l;
    double t=a/b;
    for(double i=1;i<=l;i++)
    {
        for(double j=1;j<=l;j++)
        {
            double t2=i/j;
            if(t2>=t&&minn>t2)
            {
                minn=t2;
                a1=i,b1=j;
            }
        }
    }
    cout<<a1<<' '<<b1;
    return 0;
}
